/**
 * PigeonholeSort implementation.
 * Efficient for sorting lists of integers where the number of elements is roughly the same as the number of possible key values.
 * It returns a new sorted slice without modifying the original input.
 */
func PigeonholeSort(arr []int) []int {
	if len(arr) == 0 {
		return []int{}
	}

	minVal, maxVal := arr[0], arr[0]
	for _, v := range arr {
		if v < minVal {
			minVal = v
		}
		if v > maxVal {
			maxVal = v
		}
	}

	rangeVal := maxVal - minVal + 1
	holes := make([][]int, rangeVal)

	for _, v := range arr {
		holes[v-minVal] = append(holes[v-minVal], v)
	}

	result := make([]int, 0, len(arr))
	for _, hole := range holes {
		result = append(result, hole...)
	}

	return result
}

import java.util.ArrayList;
import java.util.Arrays;
import java.util.List;

public class PigeonholeSort {
    /**
     * Pigeonhole Sort implementation.
     * Efficient for sorting lists of integers where the number of elements is roughly the same as the number of possible key values.
     * @param arr the input array
     * @return a sorted copy of the array
     */
    public static int[] sort(int[] arr) {
        if (arr == null || arr.length == 0) {
            return new int[0];
        }

        int min = arr[0];
        int max = arr[0];

        for (int i = 1; i < arr.length; i++) {
            if (arr[i] < min) min = arr[i];
            if (arr[i] > max) max = arr[i];
        }

        int range = max - min + 1;
        List<List<Integer>> holes = new ArrayList<>(range);
        for (int i = 0; i < range; i++) {
            holes.add(new ArrayList<>());
        }

        for (int i = 0; i < arr.length; i++) {
            holes.get(arr[i] - min).add(arr[i]);
        }

        int[] result = new int[arr.length];
        int index = 0;
        for (List<Integer> hole : holes) {
            for (int val : hole) {
                result[index++] = val;
            }
        }

        return result;
    }
}

