/**
 * Pigeonhole Sort implementation.
 * Efficient for sorting lists of integers where the number of elements is roughly the same as the number of possible key values.
 */
object PigeonholeSort {
    fun sort(arr: IntArray): IntArray {
        if (arr.isEmpty()) {
            return IntArray(0)
        }

        var min = arr[0]
        var max = arr[0]

        for (i in 1 until arr.size) {
            if (arr[i] < min) min = arr[i]
            if (arr[i] > max) max = arr[i]
        }

        val range = max - min + 1
        val holes = Array(range) { mutableListOf<Int>() }

        for (x in arr) {
            holes[x - min].add(x)
        }

        val result = IntArray(arr.size)
        var k = 0
        for (hole in holes) {
            for (x in hole) {
                result[k++] = x
            }
        }

        return result
    }
}

/**
 * Pigeonhole Sort implementation.
 * Efficient for sorting lists of integers where the number of elements is roughly the same as the number of possible key values.
 */
pub fn pigeonhole_sort(arr: &[i32]) -> Vec<i32> {
    if arr.is_empty() {
        return Vec::new();
    }

    let min_val = *arr.iter().min().unwrap();
    let max_val = *arr.iter().max().unwrap();
    let range = (max_val - min_val + 1) as usize;

    let mut holes: Vec<Vec<i32>> = vec![Vec::new(); range];

    for &x in arr {
        holes[(x - min_val) as usize].push(x);
    }

    let mut result = Vec::with_capacity(arr.len());
    for hole in holes {
        result.extend(hole);
    }

    result
}

