import scala.collection.mutable.ListBuffer

/**
 * Pigeonhole Sort implementation.
 * Efficient for sorting lists of integers where the number of elements is roughly the same as the number of possible key values.
 */
object PigeonholeSort {
  def sort(arr: Array[Int]): Array[Int] = {
    if (arr.isEmpty) {
      return Array.empty[Int]
    }

    val minVal = arr.min
    val maxVal = arr.max
    val range = maxVal - minVal + 1

    val holes = Array.fill(range)(ListBuffer.empty[Int])

    for (x <- arr) {
      holes(x - minVal) += x
    }

    val result = new Array[Int](arr.length)
    var k = 0
    for (hole <- holes) {
      for (x <- hole) {
        result(k) = x
        k += 1
      }
    }

    result
  }
}

/**
 * Pigeonhole Sort implementation.
 * Efficient for sorting lists of integers where the number of elements is roughly the same as the number of possible key values.
 */
public class PigeonholeSort {
    public static func sort(_ arr: [Int]) -> [Int] {
        guard !arr.isEmpty else {
            return []
        }

        let minVal = arr.min()!
        let maxVal = arr.max()!
        let range = maxVal - minVal + 1

        var holes = [[Int]](repeating: [], count: range)

        for x in arr {
            holes[x - minVal].append(x)
        }

        var result = [Int]()
        result.reserveCapacity(arr.count)
        for hole in holes {
            result.append(contentsOf: hole)
        }

        return result
    }
}

/**
 * Pigeonhole Sort implementation.
 * Efficient for sorting lists of integers where the number of elements is roughly the same as the number of possible key values.
 * @param arr the input array
 * @returns a sorted copy of the array
 */
export function pigeonholeSort(arr: number[]): number[] {
    if (arr.length === 0) {
        return [];
    }

    let min = arr[0];
    let max = arr[0];

    for (const val of arr) {
        if (val < min) min = val;
        if (val > max) max = val;
    }

    const range = max - min + 1;
    const holes: number[][] = Array.from({ length: range }, () => []);

    for (const val of arr) {
        holes[val - min].push(val);
    }

    const result: number[] = [];
    for (const hole of holes) {
        result.push(...hole);
    }

    return result;
}
